### Swift Nested Functions

Nested functions are functions defined inside the body of another function. They are hidden from the outside scope but can be called, returned, or passed as arguments by the enclosing function.

**Nested Function Syntax:**

```swift
func outerFunction() {
    // Nested function
    func innerFunction() {
        print("Inside inner function")
    }

    innerFunction()  // Can call from outer scope
}

outerFunction()
// innerFunction()  // Error: not in scope
```

**Capturing Values:**

Nested functions can capture variables from the enclosing scope:

```swift
func makeCounter() -> () -> Int {
    var count = 0

    func increment() -> Int {
        count += 1  // Captures count
        return count
    }

    return increment
}

let counter = makeCounter()
print(counter())  // 1
print(counter())  // 2
print(counter())  // 3
```

**Use Cases:**

| Use Case | Description |
|----------|-------------|
| Encapsulation | Hide helper functions from external scope |
| Closure factories | Return specialized functions |
| Recursive helpers | Organize recursive logic |
| Scoped utilities | Short-lived helper functions |

```swift
// Nested functions for organization
func processNumbers(_ numbers: [Int]) -> [Int] {
    func isPrime(_ n: Int) -> Bool {
        guard n > 1 else { return false }
        for i in 2..<n {
            if n % i == 0 { return false }
        }
        return true
    }

    func square(_ n: Int) -> Int {
        return n * n
    }

    return numbers.filter(isPrime).map(square)
}
```

> **Key Point:** Nested functions capture and store references to variables from their enclosing scope. This is similar to closures and can create function factories.

```swift
// Returning a nested function
func makeMultiplier(_ factor: Int) -> (Int) -> Int {
    func multiplier(_ input: Int) -> Int {
        return input * factor
    }
    return multiplier
}

let double = makeMultiplier(2)
print(double(5))  // 10
```

codeExample:
import Foundation

// Nested functions for validation
func validateUser(name: String, age: Int, email: String) -> Bool {
    func isValidName(_ name: String) -> Bool {
        !name.trimmingCharacters(in: .whitespaces).isEmpty
    }

    func isValidAge(_ age: Int) -> Bool {
        age >= 0 && age <= 150
    }

    func isValidEmail(_ email: String) -> Bool {
        email.contains("@") && email.contains(".")
    }

    return isValidName(name) && isValidAge(age) && isValidEmail(email)
}

print(validateUser(name: "Alice", age: 30, email: "alice@example.com"))  // true
print(validateUser(name: "", age: 200, email: "invalid"))               // false

// Function factory with nested functions
func createFormatter(_ prefix: String, _ suffix: String) -> (String) -> String {
    func format(_ input: String) -> String {
        "\(prefix)\(input)\(suffix)"
    }
    return format
}

let bracketed = createFormatter("[", "]")
print(bracketed("Swift"))  // [Swift]
